            if k.isalpha():
                lettered=True
            else:
                lettered=False
    n=""
    for k in a:
        if k in "0123456789":
            n+=k
        elif not k.isdigit() and n != "":
            z=0
            for y in n:
                if y=="0":
                    z+=1
                else:
                    z=0
            m=n[:-z]+f'e{z}'
            if z>0 and len(m)<len(n):
                a=a.replace(n,m)
            n=""
    if n>"":
        z=0
        for y in n:
            if y=="0":
                z+=1
